     5→namespace zlang {
     6→
     7→// ============================================================================
     8→// 생성자
     9→// ============================================================================
    10→
    11→Parser::Parser(const std::vector<Token>& tok)
    12→    : tokens(tok), current(0) {
    13→}
    14→
    15→// ============================================================================
    16→// 【 진입점: parse() 】
    17→// ============================================================================
    18→
    19→std::shared_ptr<ProgramNode> Parser::parse() {
    20→    return parseProgram();
    21→}
    22→
    23→// ============================================================================
    24→// 【 Program & Function 파싱 】
    25→// ============================================================================
    26→
    27→std::shared_ptr<ProgramNode> Parser::parseProgram() {
    28→    auto program = std::make_shared<ProgramNode>();
    29→
    30→    while (!isAtEnd()) {
    31→        if (check(TokenType::KW_FN)) {
    32→            auto func = parseFunction();
    33→            if (func) {
    34→                program->functions.push_back(func);
    35→            }
    36→        } else {
    37→            reportError("Expected 'fn' at top level");
    38→            synchronize();
    39→            advance();
    40→        }
    41→    }
    42→
    43→    return program;
    44→}
    45→
    46→std::shared_ptr<FunctionNode> Parser::parseFunction() {
    47→    if (!match(TokenType::KW_FN)) {
    48→        reportError("Expected 'fn'");
    49→        return nullptr;
    50→    }
    51→
    52→    Token name_token = consume(TokenType::IDENTIFIER, "Expected function name");
    53→    std::string func_name = name_token.lexeme;
    54→
    55→    consume(TokenType::LPAREN, "Expected '(' after function name");
    56→    auto params = parseParameters();
    57→    consume(TokenType::RPAREN, "Expected ')' after parameters");
    58→
    59→    consume(TokenType::ARROW, "Expected '->' before return type");
    60→    Type return_type = parseType();
    61→
    62→    auto block = parseBlock();
    63→    if (!block) {
    64→        return nullptr;
    65→    }
    66→
    67→    return std::make_shared<FunctionNode>(func_name, params, return_type, block);
    68→}
    69→
    70→std::vector<Parameter> Parser::parseParameters() {
    71→    std::vector<Parameter> params;
    72→
    73→    if (check(TokenType::RPAREN)) {
    74→        return params;  // 파라미터 없음
    75→    }
    76→
    77→    do {
    78→        Token param_name = consume(TokenType::IDENTIFIER, "Expected parameter name");
    79→        consume(TokenType::COLON, "Expected ':' after parameter name");
    80→        Type param_type = parseType();
    81→
    82→        params.push_back({param_name.lexeme, param_type});
    83→
    84→        if (!match(TokenType::COMMA)) {
    85→            break;
    86→        }
    87→    } while (!check(TokenType::RPAREN));
    88→
    89→    return params;
    90→}
    91→
    92→Type Parser::parseType() {
    93→    Type type;
    94→
    95→    // 포인터 타입: &T
    96→    if (match(TokenType::AMPERSAND)) {
    97→        type.is_pointer = true;
    98→        auto pointee = std::make_unique<Type>(parseType());
    99→        type.pointee_type = pointee.release();
   100→        return type;
   101→    }
   102→
   103→    // 배열 타입: [T; N]
   104→    if (match(TokenType::LBRACKET)) {
   105→        type.is_array = true;
   106→        auto elem_type = std::make_unique<Type>(parseType());
   107→        type.element_type = elem_type.release();
   108→
   109→        consume(TokenType::SEMICOLON, "Expected ';' in array type");
   110→
   111→        Token size_token = consume(TokenType::INTEGER, "Expected array size");
   112→        type.array_size = std::stoi(size_token.lexeme);
   113→
   114→        consume(TokenType::RBRACKET, "Expected ']' after array type");
   115→        return type;
   116→    }
   117→
   118→    // 기본 타입
   119→    type.base = tokenTypeToBuiltinType(peek().type);
   120→
   121→    if (type.base == BuiltinType::Unknown) {
   122→        // 커스텀 타입일 수 있음 (현재는 지원하지 않음)
   123→        reportError("Unknown type: " + peek().lexeme);
   124→    }
   125→
   126→    advance();
   127→    return type;
   128→}
   129→
   130→// ============================================================================
   131→// 【 Statement 파싱 】
   132→// ============================================================================
   133→
   134→std::shared_ptr<ASTNode> Parser::parseStatement() {
   135→    if (check(TokenType::KW_LET)) {
   136→        return parseVarDecl();
   137→    }
   138→    if (check(TokenType::KW_IF)) {
   139→        return parseIfStatement();
   140→    }
   141→    if (check(TokenType::KW_WHILE)) {
   142→        return parseWhileStatement();
   143→    }
   144→    if (check(TokenType::KW_RETURN)) {
   145→        return parseReturnStatement();
   146→    }
   147→    // 【 Step 3: try-catch-finally 파싱 】
   148→    if (check(TokenType::KW_TRY)) {
   149→        return parseTryCatch();
   150→    }
   151→    if (check(TokenType::LBRACE)) {
   152→        return parseBlock();
   153→    }
   154→
   155→    // Expression statement
   156→    auto expr = parseExpression();
   157→    match(TokenType::SEMICOLON);
   158→    return expr;
   159→}
   160→
   161→std::shared_ptr<VarDeclNode> Parser::parseVarDecl() {
   162→    if (!match(TokenType::KW_LET)) {
   163→        reportError("Expected 'let'");
   164→        return nullptr;
   165→    }
   166→
   167→    Token var_name = consume(TokenType::IDENTIFIER, "Expected variable name");
   168→    consume(TokenType::COLON, "Expected ':' after variable name");
   169→
   170→    Type var_type = parseType();
   171→
   172→    consume(TokenType::ASSIGN, "Expected '=' after type");
   173→    auto init_expr = parseExpression();
   174→
   175→    consume(TokenType::SEMICOLON, "Expected ';' after variable declaration");
   176→
   177→    auto var_decl = std::make_shared<VarDeclNode>(var_name.lexeme, var_type, init_expr);
   178→
   179→    return var_decl;
   180→}
   181→
   182→std::shared_ptr<BlockNode> Parser::parseBlock() {
   183→    if (!match(TokenType::LBRACE)) {
   184→        reportError("Expected '{'");
   185→        return nullptr;
   186→    }
   187→
   188→    auto block = std::make_shared<BlockNode>();
   189→
   190→    while (!check(TokenType::RBRACE) && !isAtEnd()) {
   191→        auto stmt = parseStatement();
   192→        if (stmt) {
   193→            block->statements.push_back(stmt);
   194→        }
   195→    }
   196→
   197→    consume(TokenType::RBRACE, "Expected '}'");
   198→    return block;
   199→}
