   201→std::shared_ptr<IfNode> Parser::parseIfStatement() {
   202→    if (!match(TokenType::KW_IF)) {
   203→        reportError("Expected 'if'");
   204→        return nullptr;
   205→    }
   206→
   207→    auto cond = parseExpression();
   208→    auto then_block = parseBlock();
   209→
   210→    if (!then_block) {
   211→        return nullptr;
   212→    }
   213→
   214→    std::shared_ptr<BlockNode> else_block = nullptr;
   215→    if (match(TokenType::KW_ELSE)) {
   216→        else_block = parseBlock();
   217→    }
   218→
   219→    return std::make_shared<IfNode>(cond, then_block, else_block);
   220→}
   221→
   222→std::shared_ptr<WhileNode> Parser::parseWhileStatement() {
   223→    if (!match(TokenType::KW_WHILE)) {
   224→        reportError("Expected 'while'");
   225→        return nullptr;
   226→    }
   227→
   228→    auto cond = parseExpression();
   229→    auto body = parseBlock();
   230→
   231→    if (!body) {
   232→        return nullptr;
   233→    }
   234→
   235→    return std::make_shared<WhileNode>(cond, body);
   236→}
   237→
   238→std::shared_ptr<ReturnNode> Parser::parseReturnStatement() {
   239→    if (!match(TokenType::KW_RETURN)) {
   240→        reportError("Expected 'return'");
   241→        return nullptr;
   242→    }
   243→
   244→    std::shared_ptr<ASTNode> return_expr = nullptr;
   245→
   246→    // return 뒤에 식이 없을 수도 있음
   247→    if (!check(TokenType::SEMICOLON)) {
   248→        return_expr = parseExpression();
   249→    }
   250→
   251→    consume(TokenType::SEMICOLON, "Expected ';' after return statement");
   252→
   253→    auto ret = std::make_shared<ReturnNode>();
   254→    ret->value = return_expr;
   255→
   256→    return ret;
   257→}
   258→
   259→// ============================================================================
   260→// 【 Expression 파싱 (우선순위 처리) 】
   261→// ============================================================================
   262→
   263→std::shared_ptr<ASTNode> Parser::parseExpression() {
   264→    return parseAssignment();
   265→}
   266→
   267→std::shared_ptr<ASTNode> Parser::parseAssignment() {
   268→    auto expr = parseLogicalOr();
   269→
   270→    if (match(TokenType::ASSIGN)) {
   271→        auto right = parseAssignment();
   272→        return std::make_shared<BinaryOpNode>(BinaryOp::Assign, expr, right);
   273→    }
   274→
   275→    return expr;
   276→}
   277→
   278→std::shared_ptr<ASTNode> Parser::parseLogicalOr() {
   279→    auto left = parseLogicalAnd();
   280→
   281→    while (match(TokenType::OR)) {
   282→        auto right = parseLogicalAnd();
   283→        left = std::make_shared<BinaryOpNode>(BinaryOp::Or, left, right);
   284→    }
   285→
   286→    return left;
   287→}
   288→
   289→std::shared_ptr<ASTNode> Parser::parseLogicalAnd() {
   290→    auto left = parseEquality();
   291→
   292→    while (match(TokenType::AND)) {
   293→        auto right = parseEquality();
   294→        left = std::make_shared<BinaryOpNode>(BinaryOp::And, left, right);
   295→    }
   296→
   297→    return left;
   298→}
   299→
   300→std::shared_ptr<ASTNode> Parser::parseEquality() {
   301→    auto left = parseRelational();
   302→
   303→    while (check(TokenType::EQ) || check(TokenType::NE)) {
   304→        TokenType op_type = advance().type;
   305→        auto right = parseRelational();
   306→        left = std::make_shared<BinaryOpNode>(tokenTypeToBinaryOp(op_type), left, right);
   307→    }
   308→
   309→    return left;
   310→}
   311→
   312→std::shared_ptr<ASTNode> Parser::parseRelational() {
   313→    auto left = parseAdditive();
   314→
   315→    while (check(TokenType::LT) || check(TokenType::GT) ||
   316→           check(TokenType::LE) || check(TokenType::GE)) {
   317→        TokenType op_type = advance().type;
   318→        auto right = parseAdditive();
   319→        left = std::make_shared<BinaryOpNode>(tokenTypeToBinaryOp(op_type), left, right);
   320→    }
   321→
   322→    return left;
   323→}
   324→
   325→std::shared_ptr<ASTNode> Parser::parseAdditive() {
   326→    auto left = parseMultiplicative();
   327→
   328→    while (check(TokenType::PLUS) || check(TokenType::MINUS)) {
   329→        TokenType op_type = advance().type;
   330→        auto right = parseMultiplicative();
   331→        left = std::make_shared<BinaryOpNode>(tokenTypeToBinaryOp(op_type), left, right);
   332→    }
   333→
   334→    return left;
   335→}
   336→
   337→std::shared_ptr<ASTNode> Parser::parseMultiplicative() {
   338→    auto left = parseUnary();
   339→
   340→    while (check(TokenType::STAR) || check(TokenType::SLASH) ||
   341→           check(TokenType::PERCENT)) {
   342→        TokenType op_type = advance().type;
   343→        auto right = parseUnary();
   344→        left = std::make_shared<BinaryOpNode>(tokenTypeToBinaryOp(op_type), left, right);
   345→    }
   346→
   347→    return left;
   348→}
   349→
   350→std::shared_ptr<ASTNode> Parser::parseUnary() {
   351→    if (check(TokenType::NOT) || check(TokenType::MINUS) ||
   352→        check(TokenType::AMPERSAND)) {
   353→        TokenType op_type = advance().type;
   354→        auto operand = parseUnary();
   355→        return std::make_shared<UnaryOpNode>(tokenTypeToUnaryOp(op_type), operand);
   356→    }
   357→
   358→    return parsePostfix();
   359→}
   360→
   361→std::shared_ptr<ASTNode> Parser::parsePostfix() {
   362→    auto expr = parsePrimary();
   363→
   364→    while (true) {
   365→        if (match(TokenType::LBRACKET)) {
   366→            // 배열 인덱싱 (현재는 미지원)
   367→            auto index = parseExpression();
   368→            consume(TokenType::RBRACKET, "Expected ']'");
   369→            reportError("Array indexing not yet supported");
   370→            return expr;
   371→        } else if (match(TokenType::LPAREN)) {
   372→            // 함수 호출
   373→            auto args = parseArguments();
   374→            consume(TokenType::RPAREN, "Expected ')'");
   375→
   376→            if (auto ident = std::dynamic_pointer_cast<IdentifierNode>(expr)) {
   377→                expr = std::make_shared<CallNode>(ident->name, args);
   378→            } else {
   379→                reportError("Can only call identifiers");
   380→            }
   381→        } else {
   382→            break;
   383→        }
   384→    }
   385→
   386→    return expr;
   387→}
   388→
   389→std::shared_ptr<ASTNode> Parser::parsePrimary() {
   390→    // 리터럴
   391→    if (check(TokenType::INTEGER)) {
   392→        Token token = advance();
   393→        auto lit = std::make_shared<IntLiteralNode>(std::stoll(token.lexeme));
   394→        return lit;
   395→    }
   396→
   397→    if (check(TokenType::FLOAT)) {
   398→        Token token = advance();
   399→        auto lit = std::make_shared<FloatLiteralNode>(std::stod(token.lexeme));
   400→        return lit;
   401→    }
   402→
   403→    if (check(TokenType::STRING)) {
   404→        Token token = advance();
   405→        auto lit = std::make_shared<StringLiteralNode>(token.lexeme);
   406→        return lit;
   407→    }
   408→
   409→    if (match(TokenType::KW_TRUE)) {
   410→        auto lit = std::make_shared<BoolLiteralNode>(true);
   411→        return lit;
   412→    }
   413→
   414→    if (match(TokenType::KW_FALSE)) {
   415→        auto lit = std::make_shared<BoolLiteralNode>(false);
   416→        return lit;
   417→    }
   418→
   419→    // 식별자
   420→    if (check(TokenType::IDENTIFIER)) {
   421→        Token token = advance();
   422→        return std::make_shared<IdentifierNode>(token.lexeme);
   423→    }
   424→
   425→    // 괄호 식
   426→    if (match(TokenType::LPAREN)) {
   427→        auto expr = parseExpression();
   428→        consume(TokenType::RPAREN, "Expected ')'");
   429→        return expr;
   430→    }
   431→
   432→    reportError("Unexpected token: " + peek().lexeme);
   433→    return nullptr;
   434→}
   435→
   436→std::vector<std::shared_ptr<ASTNode>> Parser::parseArguments() {
   437→    std::vector<std::shared_ptr<ASTNode>> args;
   438→
   439→    if (check(TokenType::RPAREN)) {
   440→        return args;
   441→    }
   442→
   443→    do {
   444→        args.push_back(parseExpression());
   445→    } while (match(TokenType::COMMA));
   446→
   447→    return args;
   448→}
