   454→Token Parser::peek() const {
   455→    if (current < tokens.size()) {
   456→        return tokens[current];
   457→    }
   458→    return tokens.back();  // EOF
   459→}
   460→
   461→Token Parser::peekNext() const {
   462→    if (current + 1 < tokens.size()) {
   463→        return tokens[current + 1];
   464→    }
   465→    return tokens.back();  // EOF
   466→}
