   468→bool Parser::check(TokenType type) const {
   469→    return peek().type == type;
   470→}
   471→
   472→bool Parser::checkAny(const std::vector<TokenType>& types) const {
   473→    for (const auto& t : types) {
   474→        if (check(t)) return true;
   475→    }
   476→    return false;
   477→}
   478→
   479→Token Parser::advance() {
   480→    Token token = peek();
   481→    if (!isAtEnd()) {
   482→        current++;
   483→    }
   484→    return token;
   485→}
