   209→    /**
   210→     * 【 Stage 4: Code Generation (코드 생성) 】
   211→     *
   212→     * 현재 상태: 2.4 단계 구현 완료 ✅
   213→     * CodeGenerator.cpp를 통한 LLVM IR 생성
   214→     */
   215→    LLVMModuleRef performCodeGeneration(const std::shared_ptr<ProgramNode>& ast) {
   216→        if (verbose) {
   217→            std::cout << "\n【 Stage 4: Code Generation (코드 생성) 】" << std::endl;
   218→        }
   219→
   220→        // CodeGenerator를 클래스 멤버로 저장 (생명주기 관리)
   221→        codegen = std::make_unique<CodeGenerator>();
   222→        LLVMModuleRef module = codegen->generate(ast);
   223→
   224→        if (!module) {
   225→            std::cerr << "❌ 코드 생성 실패" << std::endl;
   226→            const auto& errors = codegen->getErrors();
   227→            for (const auto& err : errors) {
   228→                std::cerr << "  - " << err << std::endl;
   229→            }
   230→            return nullptr;
   231→        }
   232→
   233→        if (verbose) {
   234→            std::cout << "✅ LLVM IR 생성 완료" << std::endl;
   235→        }
   236→
   237→        return module;
   238→    }
