    26→    std::string typed_ast;
    27→    for (const auto& func : functions) {
    28→        typed_ast += typeCheck(func) + "\n";
    29→    }
    30→
    31→    // Step 3: Generate IR
    32→    std::string ir = generateIR(typed_ast);
    33→    if (ir.empty()) {
    34→        last_error_ = "IR generation failed";
    35→        return false;
    36→    }
    37→
    38→    // Step 4: Write IR to file
    39→    std::ofstream ir_file(output_file + ".ll");
    40→    ir_file << ir;
    41→    ir_file.close();
    42→
    43→    // Step 5: Compile with llc
    44→    std::string obj_file = output_file + ".o";
    45→    std::string compile_cmd = "llc -filetype=obj -o " + obj_file + " " + output_file + ".ll";
    46→    int ret = system(compile_cmd.c_str());
    47→
    48→    if (ret != 0) {
    49→        last_error_ = "LLVM compilation failed";
    50→        return false;
    51→    }
    52→
    53→    // Step 6: Link with clang
    54→    std::string link_cmd = "clang -o " + output_file + " " + obj_file;
    55→    ret = system(link_cmd.c_str());
    56→
    57→    if (ret != 0) {
    58→        last_error_ = "Linking failed";
    59→        return false;
    60→    }
    61→
    62→    return true;
    63→}
