    65→std::string CompilerPipeline::typeCheck(const std::string& ast) {
    66→    // 간단한 구현: 함수 정의 파싱
    67→    // 예: "fn add(a, b) { a + b }"
    68→
    69→    std::regex func_regex(R"(fn\s+(\w+)\s*\(([^)]*)\)\s*\{([^}]*)\})");
    70→    std::smatch match;
    71→
    72→    if (std::regex_search(ast, match, func_regex)) {
    73→        std::string func_name = match[1].str();
    74→        std::string params = match[2].str();
    75→        std::string body = match[3].str();
    76→
    77→        // 매개변수 파싱 (간단화)
    78→        std::vector<std::string> param_names, param_types;
    79→
    80→        if (!params.empty()) {
    81→            // "a, b" → params
    82→            std::istringstream iss(params);
    83→            std::string param;
    84→            while (std::getline(iss, param, ',')) {
    85→                // 공백 제거
    86→                param.erase(0, param.find_first_not_of(" \t"));
    87→                param.erase(param.find_last_not_of(" \t") + 1);
    88→
    89→                param_names.push_back(param);
    90→                param_types.push_back("i64");  // 기본값
    91→            }
    92→        }
    93→
    94→        // 바인딩
    95→        for (const auto& param : param_names) {
    96→            type_checker_->bindVariable(param, "i64");
    97→        }
    98→
    99→        // 반환 타입 추론
   100→        std::string return_type = type_checker_->inferExprType(body);
   101→
   102→        // 검증된 함수 등록
   103→        type_checker_->registerConcreteFunction(func_name, return_type, param_types);
   104→
   105→        return ast;  // 타입 체크 완료
   106→    }
   107→
   108→    return ast;
   109→}
