    33→    for (const auto& [name, info] : wcet_map) {
    34→        if (info.cycles > max_wcet) {
    35→            max_wcet = info.cycles;
    36→            critical_func = name;
    37→        }
    38→    }
    39→
    40→    if (!critical_func.empty()) {
    41→        wcet_map[critical_func].is_critical_path = true;
