    52→unsigned long WCETAnalyzer::analyzeFunction(const std::shared_ptr<FunctionNode>& func) {
    53→    if (!func) return 0;
    54→
    55→    unsigned long total_cycles = 0;
    56→    unsigned long exception_cycles = 0;
    57→
    58→    // 함수 프롤로그/에필로그: 10 사이클
    59→    total_cycles += 10;
    60→
    61→    // 함수 본체 분석
    62→    if (func->body) {
    63→        total_cycles += analyzeNode(func->body, 0);
    64→    }
    65→
    66→    // 예외 처리 오버헤드: try-catch가 있으면 추가
    67→    // 간단한 추정: exception handler 호출 ~50사이클
    68→    exception_cycles = 50;
    69→
    70→    WCETInfo info;
    71→    info.node_name = func->func_name;
    72→    info.cycles = total_cycles;
    73→    info.exception_cycles = exception_cycles;
    74→
    75→    wcet_map[func->func_name] = info;
    76→
    77→    return total_cycles;
