    87→    unsigned long cycles = 0;
    88→
    89→    switch (node->type) {
    90→        // 【 리터럴: 1 사이클 】
    91→        case ASTNode::NodeType::IntLiteral:
    92→        case ASTNode::NodeType::FloatLiteral:
    93→        case ASTNode::NodeType::BoolLiteral:
    94→        case ASTNode::NodeType::StringLiteral:
