    97→
    98→        // 【 식별자 로드: 2 사이클 】
    99→        case ASTNode::NodeType::Identifier:
   100→            cycles = 2;
   101→            break;
   102→
   103→        // 【 이항 연산: 4-6 사이클 】
   104→        case ASTNode::NodeType::BinaryOp: {
   105→            auto binop = std::dynamic_pointer_cast<BinaryOpNode>(node);
   106→            if (binop) {
