    if (verbose) {
        std::cout << "\n【 Stage 4: Code Generation 】" << std::endl;
    }

    codegen = std::make_unique<CodeGenerator>();
    LLVMModuleRef module = codegen->generate(ast);  // 🔴 METHOD NOT FOUND

    if (!module) {
        // ...
